```js
// debounce.js — fixed + self-checking

function debounce(fn, ms) {
  let t;
  return function (...a) {
    clearTimeout(t);
    t = setTimeout(() => fn.apply(this, a), ms); // forward args AND `this`
  };
}

// ---- test with oracle ----
const calls = [];
const d = debounce((...a) => calls.push(a), 20);

d("a"); d("b"); d("c"); // rapid fire: only the last should survive, with its args

setTimeout(() => {
  const oracle = { count: 1, lastArgs: ["c"] };          // expected
  const actual = { count: calls.length, lastArgs: calls[0] };
  const argsOk = JSON.stringify(actual) === JSON.stringify(oracle);
  console.log("oracle:", JSON.stringify(oracle));
  console.log("actual:", JSON.stringify(actual));

  // bonus: `this` is preserved for debounced methods
  const obj = { v: 42, got: null };
  obj.run = debounce(function (x) { obj.got = this.v + x; }, 10);
  obj.run(8);
  setTimeout(() => {
    const thisOk = obj.got === 50;
    console.log("args:", argsOk ? "PASS" : "FAIL", "| this-binding:", thisOk ? "PASS" : "FAIL");
    process.exit(argsOk && thisOk ? 0 : 1);
  }, 30);
}, 60);

module.exports = debounce;
```

Run it with `node debounce.js`. Expected output:

```
oracle: {"count":1,"lastArgs":["c"]}
actual: {"count":1,"lastArgs":["c"]}
args: PASS | this-binding: PASS
